import { Component, Input } from '@angular/core';
import { RouterLink } from '@angular/router';
import { DecimalPipe } from '@angular/common';
import { Product } from '../../core/models/product.model';

@Component({
  selector: 'app-product-card',
  standalone: true,
  imports: [RouterLink, DecimalPipe],
  styleUrl: './product-card.component.scss',
  template: `
    <article class="card" [routerLink]="['/product', product.id]">
      <div class="card-image">
        @if (product.imageUrls?.length) {
          <img [src]="product.imageUrls[0]" [alt]="product.name" loading="lazy" />
          @if (product.imageUrls.length > 1) {
            <img class="img-hover" [src]="product.imageUrls[1]" [alt]="product.name" loading="lazy" />
          }
        } @else {
          <div class="img-placeholder">
            <span>{{ product.name[0] }}</span>
          </div>
        }
        @if (!product.inStock) {
          <span class="badge-soldout">Sold Out</span>
        }
        @if (product.featured && product.inStock) {
          <span class="badge-featured">Featured</span>
        }
      </div>
      <div class="card-info">
        <h3 class="card-name">{{ product.name }}</h3>
        <p class="card-price">{{ product.price | number:'1.2-2' }} {{ product.currency }}</p>
        @if (product.availableSizes?.length) {
          <div class="card-sizes">
            @for (size of product.availableSizes; track size) {
              <span class="size-dot">{{ size }}</span>
            }
          </div>
        }
      </div>
    </article>
  `
})
export class ProductCardComponent {
  @Input({ required: true }) product!: Product;
}
